#include <stdio.h>
#include <stdint.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    const unsigned long long INF = 4000000000000000000ULL; // 4e18
    while(T--){
        int k; scanf("%d", &k);
        unsigned long long stems = 1ULL; // stems at current level
        int ok = 1;
        for(int i=0;i<k;i++){
            unsigned int leaf; scanf("%u", &leaf);
            if(!ok) continue; // still consume input
            if(leaf > stems){ ok = 0; continue; }
            unsigned long long next = 2ULL * (stems - leaf);
            if(next > INF) next = INF;
            stems = next;
        }
        printf(ok ? "Yes\n" : "No\n");
    }
    return 0;
}

