import java.io.*;
import java.util.*;

public class Main {
    private static final long INF = 4_000_000_000_000_000_000L; // 4e18
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int k = fs.nextInt();
            long stems = 1L;
            boolean ok = true;
            for (int i = 0; i < k; i++) {
                long leaf = fs.nextLong();
                if (!ok) continue;
                if (leaf > stems) {
                    ok = false;
                    continue;
                }
                long next = 2L * (stems - leaf);
                if (next > INF) next = INF;
                stems = next;
            }
            sb.append(ok ? "Yes" : "No").append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c;
            while ((c = readByte()) <= ' ') {
                if (c == -1) return -1;
            }
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

