#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out = []
    INF = 4_000_000_000_000_000_000  # 4e18
    for _ in range(T):
        k = next(it)
        stems = 1
        ok = True
        for _ in range(k):
            leaf = next(it)
            if not ok:
                continue
            if leaf > stems:
                ok = False
                continue
            stems = 2 * (stems - leaf)
            if stems > INF:
                stems = INF
        out.append('Yes' if ok else 'No')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

